BEGIN TRANSACTION;
CREATE TABLE "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE "core_manutencao" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "data" datetime NOT NULL, "tipo" varchar(50) NOT NULL, "custo" real NULL, "descricao" text NULL, "veiculo_id" bigint NOT NULL REFERENCES "core_veiculo" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "core_motorista" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "nome" varchar(255) NOT NULL, "cnh" varchar(50) NOT NULL UNIQUE, "categoria_cnh" varchar(10) NULL, "status" varchar(20) NOT NULL, "classificacao" varchar(20) NOT NULL, "pontuacao" real NOT NULL, "telefone" varchar(20) NULL);
CREATE TABLE "core_telemetria" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "data_hora" datetime NOT NULL, "latitude" real NULL, "longitude" real NULL, "velocidade" real NULL, "consumo_combustivel" real NULL, "rpm" integer NULL, "veiculo_id" bigint NOT NULL REFERENCES "core_veiculo" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "core_usuario" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "cargo" varchar(20) NOT NULL);
CREATE TABLE "core_usuario_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "usuario_id" bigint NOT NULL REFERENCES "core_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "core_usuario_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "usuario_id" bigint NOT NULL REFERENCES "core_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "core_veiculo" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "placa" varchar(20) NOT NULL UNIQUE, "modelo" varchar(100) NOT NULL, "ano" integer NULL, "status" varchar(20) NOT NULL, "cidade" varchar(100) NULL, "uf" varchar(2) NULL, "lat" real NULL, "lng" real NULL, "nivel_combustivel" real NULL, "saude_pneus" real NULL, "sketchfab_id" varchar(100) NULL, "detalhes_manutencao" text NULL, "preco_compra" real NULL, "receita_mensal" real NULL, "manutencao_mensal" real NULL, "combustivel_mensal" real NULL, "motorista_id" bigint NULL REFERENCES "core_motorista" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" bigint NOT NULL REFERENCES "core_usuario" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE UNIQUE INDEX "django_content_type_app_label_model_76bd3d3b_uniq" ON "django_content_type" ("app_label", "model");
CREATE UNIQUE INDEX "auth_group_permissions_group_id_permission_id_0cd325b0_uniq" ON "auth_group_permissions" ("group_id", "permission_id");
CREATE INDEX "auth_group_permissions_group_id_b120cbf9" ON "auth_group_permissions" ("group_id");
CREATE INDEX "auth_group_permissions_permission_id_84c5c92e" ON "auth_group_permissions" ("permission_id");
CREATE UNIQUE INDEX "auth_permission_content_type_id_codename_01ab375a_uniq" ON "auth_permission" ("content_type_id", "codename");
CREATE INDEX "auth_permission_content_type_id_2f476e4b" ON "auth_permission" ("content_type_id");
CREATE UNIQUE INDEX "core_usuario_groups_usuario_id_group_id_bde3c750_uniq" ON "core_usuario_groups" ("usuario_id", "group_id");
CREATE INDEX "core_usuario_groups_usuario_id_97385234" ON "core_usuario_groups" ("usuario_id");
CREATE INDEX "core_usuario_groups_group_id_55312a9a" ON "core_usuario_groups" ("group_id");
CREATE UNIQUE INDEX "core_usuario_user_permissions_usuario_id_permission_id_7a048d24_uniq" ON "core_usuario_user_permissions" ("usuario_id", "permission_id");
CREATE INDEX "core_usuario_user_permissions_usuario_id_ce4108a7" ON "core_usuario_user_permissions" ("usuario_id");
CREATE INDEX "core_usuario_user_permissions_permission_id_7f881653" ON "core_usuario_user_permissions" ("permission_id");
CREATE INDEX "core_veiculo_motorista_id_7c33168a" ON "core_veiculo" ("motorista_id");
CREATE INDEX "core_telemetria_veiculo_id_58b58355" ON "core_telemetria" ("veiculo_id");
CREATE INDEX "core_manutencao_veiculo_id_4c054d27" ON "core_manutencao" ("veiculo_id");
CREATE INDEX "django_admin_log_content_type_id_c4bce8eb" ON "django_admin_log" ("content_type_id");
CREATE INDEX "django_admin_log_user_id_c564eba6" ON "django_admin_log" ("user_id");
CREATE INDEX "django_session_expire_date_a5c62663" ON "django_session" ("expire_date");
DELETE FROM "sqlite_sequence";
COMMIT;